        for(int i=0;i<N;i++){
            cin>>g[i];
            for(int j=0;j<M;j++) if(g[i][j]=='1'){
                minR=min(minR,i);
                maxR=max(maxR,i);
                minC=min(minC,j);
                maxC=max(maxC,j);
            }
        }
        bool ok=true;
        for(int i=minR;i<=maxR && ok;i++)
            for(int j=minC;j<=maxC;j++)
                if(g[i][j]!='1'){ ok=false; break; }
        cout<<(ok?"YES":"NO")<<'\n';
    }
    return 0;
}

