import sys
def solve():
    data = sys.stdin.read().splitlines()
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N, M = map(int, next(it).split())
        grid = []
        min_r, max_r = N, -1
        min_c, max_c = M, -1
        for i in range(N):
            row = next(it).strip()
            grid.append(row)
            for j,ch in enumerate(row):
                if ch == '1':
                    if i < min_r: min_r = i
                    if i > max_r: max_r = i
                    if j < min_c: min_c = j
                    if j > max_c: max_c = j
        ok = True
        for i in range(min_r, max_r+1):
            for j in range(min_c, max_c+1):
                if grid[i][j] != '1':
                    ok = False
                    break
            if not ok:
                break
        out.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

