  const [Nstr, Mstr] = input[idx++].trim().split(/\s+/);
  const N = parseInt(Nstr, 10);
  const M = parseInt(Mstr, 10);
  const grid = [];
  let minR = N, maxR = -1, minC = M, maxC = -1;
  for (let i = 0; i < N; i++) {
    const row = input[idx++].trim();
    grid.push(row);
    for (let j = 0; j < M; j++) {
      if (row[j] === '1') {
        if (i < minR) minR = i;
        if (i > maxR) maxR = i;
        if (j < minC) minC = j;
        if (j > maxC) maxC = j;
      }
    }
  }
  let ok = true;
  for (let i = minR; i <= maxR && ok; i++) {
    for (let j = minC; j <= maxC; j++) {
      if (grid[i][j] !== '1') { ok = false; break; }
    }
  }
  results.push(ok ? 'YES' : 'NO');
}
